def lcs_length(a, b):
    # dynamic programming for LCS
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                if dp[j] < dp[j-1]:
                    dp[j] = dp[j-1]
            prev = tmp
    return dp[m]
def sim_lcs_min(a,b):
    a2, b2 = normalize_ar(a), normalize_ar(b)
    l = lcs_length(a2, b2)
    return l / min(len(a2), len(b2))
